<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Models\Role; use App\Models\User; use App\Services\ActivityLogger; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class UserController extends Controller { public function index():View{return view('admin.users.index',['users'=>User::with('nexusRole')->latest()->paginate(25)]);} public function edit(User $user):View{return view('admin.users.edit',['member'=>$user,'roles'=>Role::orderBy('name')->get()]);} public function update(Request $request,User $user,ActivityLogger $log):RedirectResponse {abort_if($user->role==='owner'&&$user->id!==auth()->id(),403);$data=$request->validate(['name'=>['required','string','max:100'],'role_id'=>['nullable','exists:roles,id'],'status'=>['required','in:active,suspended,banned'],'locale'=>['required','in:bg,en']]);$before=$user->only(['role_id','status']);$user->update($data);$log->record('user.updated',$user,['before'=>$before,'after'=>$user->only(['role_id','status'])]);return back()->with('success','Потребителят е обновен.');} }
